import React from "react";
import { SectionLabel, sectionTitle } from "./Skills";

const cardColors = ["var(--accent)", "var(--accent2)", "var(--accent3)"];

export default function Projects({ projects }) {
  return (
    <>
      <style>{`
        .proj-section {
          padding: clamp(2.5rem, 6vw, 5rem) clamp(1.25rem, 5vw, 4rem);
        }
        .proj-grid {
          display: grid;
          grid-template-columns: repeat(3, 1fr);
          gap: 1.1rem;
        }
        .proj-card {
          background: var(--surface);
          border: 1px solid var(--border);
          border-radius: var(--radius);
          padding: clamp(1.1rem, 2.5vw, 1.75rem);
          display: flex;
          flex-direction: column;
          transition: border-color 0.3s, transform 0.3s, box-shadow 0.3s;
          cursor: default;
          overflow: hidden;
        }
        .proj-bar {
          height: 3px;
          border-radius: 99px;
          margin-bottom: 1rem;
        }
        .proj-name {
          font-family: var(--font-display);
          font-weight: 700;
          font-size: clamp(0.9rem, 1.6vw, 1.1rem);
          margin-bottom: 0.65rem;
          line-height: 1.3;
          letter-spacing: -0.01em;
        }
        .proj-desc {
          font-size: clamp(0.78rem, 1.2vw, 0.875rem);
          color: var(--muted);
          line-height: 1.65;
          margin-bottom: 1rem;
          flex: 1;
        }
        .proj-metrics {
          display: flex;
          flex-wrap: wrap;
          gap: 0.4rem;
          margin-bottom: 0.9rem;
        }
        .proj-metric {
          border-radius: 99px;
          padding: 3px 10px;
          font-size: clamp(0.66rem, 1vw, 0.75rem);
          font-weight: 600;
        }
        .proj-stack {
          display: flex;
          flex-wrap: wrap;
          gap: 0.35rem;
        }
        .stack-tag {
          background: var(--surface2);
          border: 1px solid var(--border);
          border-radius: 5px;
          padding: 3px 9px;
          font-size: clamp(0.65rem, 0.9vw, 0.75rem);
          color: var(--muted);
          white-space: nowrap;
        }

        /* Tablet — 2 cols */
        @media (max-width: 900px) {
          .proj-grid { grid-template-columns: repeat(2, 1fr); }
        }
        /* Mobile — 1 col */
        @media (max-width: 560px) {
          .proj-grid { grid-template-columns: 1fr; }
          .proj-name { font-size: 1rem; }
          .proj-desc { font-size: 0.85rem; }
        }
      `}</style>

      <section className="proj-section" id="projects">
        <SectionLabel text="Portfolio" />
        <h2 style={sectionTitle}>Featured Projects</h2>

        <div className="proj-grid">
          {projects.map((p, i) => {
            const color = cardColors[i % cardColors.length];
            return (
              <div key={i} className="proj-card"
                onMouseEnter={e => { e.currentTarget.style.borderColor = color; e.currentTarget.style.transform = "translateY(-4px)"; e.currentTarget.style.boxShadow = `0 16px 40px ${color.replace("var(--accent)", "#00e5ff").replace("var(--accent2)", "#7c3aed").replace("var(--accent3)", "#f59e0b")}18`; }}
                onMouseLeave={e => { e.currentTarget.style.borderColor = "var(--border)"; e.currentTarget.style.transform = "none"; e.currentTarget.style.boxShadow = "none"; }}
              >
                <div className="proj-bar" style={{ background: `linear-gradient(90deg, ${color}, transparent)` }} />
                <div className="proj-name">{p.name}</div>
                <div className="proj-desc">{p.description}</div>
                <div className="proj-metrics">
                  {p.metrics.map((m, j) => (
                    <span key={j} className="proj-metric" style={{ background: `${color}15`, border: `1px solid ${color}30`, color }}>{m}</span>
                  ))}
                </div>
                <div className="proj-stack">
                  {p.stack.map((s, j) => <span key={j} className="stack-tag">{s}</span>)}
                </div>
              </div>
            );
          })}
        </div>
      </section>
    </>
  );
}
